package com.example.app.waitlist; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import java.time.*; public interface BookingHoldRepository extends JpaRepository<BookingHold,Long>{ @Query("select count(h)>0 from BookingHold h where h.company.id=:companyId and h.status='ACTIVE' and h.expiresAt>:now and h.slotStart<:end and h.slotEnd>:start and (:employeeId is null or h.employee.id=:employeeId)") boolean existsActiveOverlap(@Param("companyId")Long companyId,@Param("employeeId")Long employeeId,@Param("start")LocalDateTime start,@Param("end")LocalDateTime end,@Param("now")LocalDateTime now); }